import{_ as t,o as a,c as i,a4 as r}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"Silicates — Chain / Band (Inosilicates)","description":"","frontmatter":{"title":"Silicates — Chain / Band (Inosilicates)","mineralGroup":"silicates-chain"},"headers":[],"relativePath":"mineral-groups/silicates-chain.md","filePath":"mineral-groups/silicates-chain.md","lastUpdated":1784176423000}'),s={name:"mineral-groups/silicates-chain.md"};function n(d,e,o,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="silicates-—-chain-band-inosilicates" tabindex="-1">Silicates — Chain / Band (Inosilicates) <a class="header-anchor" href="#silicates-—-chain-band-inosilicates" aria-label="Permalink to &quot;Silicates — Chain / Band (Inosilicates)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Chain silicates encompass two major gem-bearing families:</p><ul><li><strong>Pyroxenes (single chain)</strong>: jadeite, diopside, spodumene (kunzite, hiddenite)</li><li><strong>Amphiboles (double chain)</strong>: nephrite, actinolite, tremolite &quot;Jade&quot; includes both jadeite (a pyroxene) and nephrite (an amphibole) — chemically and structurally distinct despite shared cultural identity.</li></ul><h2 id="formula-class" tabindex="-1">Formula Class <a class="header-anchor" href="#formula-class" aria-label="Permalink to &quot;Formula Class&quot;">​</a></h2><p>M·SiO₃ / M₇Si₈O₂₂(OH)₂</p><h2 id="crystal-structure" tabindex="-1">Crystal Structure <a class="header-anchor" href="#crystal-structure" aria-label="Permalink to &quot;Crystal Structure&quot;">​</a></h2><p>[SiO₄] tetrahedra share two oxygens to form single chains (pyroxenes) or 2:1 double chains (amphiboles). Chains are bridged by metal cations (Ca, Mg, Fe) and OH⁻ groups. Chain structure running along the c-axis produces characteristic prismatic or fibrous crystal habits.</p><h2 id="representative-gem-species" tabindex="-1">Representative Gem Species <a class="header-anchor" href="#representative-gem-species" aria-label="Permalink to &quot;Representative Gem Species&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Formula</th><th>Subgroup</th></tr></thead><tbody><tr><td>Jadeite (Burmese Jade) / 翡翠</td><td>NaAlSi₂O₆</td><td>pyroxene</td></tr><tr><td>Nephrite / 软玉</td><td>Ca₂(Mg,Fe)₅Si₈O₂₂(OH)₂</td><td>amphibole</td></tr><tr><td>Spodumene (Kunzite) / 孔赛石</td><td>LiAlSi₂O₆</td><td>pyroxene</td></tr><tr><td>Spodumene (Hiddenite) / 翠绿锂辉石</td><td>LiAlSi₂O₆ + Cr</td><td>pyroxene</td></tr><tr><td>Diopside / 透辉石</td><td>CaMgSi₂O₆</td><td>pyroxene</td></tr><tr><td>Rhodonite / 蔷薇辉石</td><td>MnSiO₃</td><td>pyroxenoid</td></tr><tr><td>Actinolite / 阳起石</td><td>Ca₂(Mg,Fe)₅Si₈O₂₂(OH)₂</td><td>amphibole</td></tr></tbody></table><p><em>See the <a href="./intro.html">mineral group overview</a>.</em></p>',11)])])}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
